# Deobfuscated Code

After resolving all the string lookups, base64 decoding, and renaming variables, here's the clean version:

```javascript
// Constants
var TAU = 6.283;           // ≈ 2π (full circle in radians)
var GOLDEN_RATIO = 1.618;  // φ (golden ratio)
var SQRT_HALF = 0.707;     // ≈ 1/√2

// Simulation parameters
var simParams = {
    attractionStrength: 4000,   // repulsion force numerator between all node pairs
    springCoeff: 0.004,         // default spring stiffness for edges
    amplification: 0.92,        // velocity damping factor per tick (friction)
    centerGravity: 0.0003,      // strength pulling nodes toward center (400, 300)
    streamCapacity: 40,         // max number of particles alive at once
    streamDecay: 0.04,          // particle drag/friction factor
    theta: 0.06                 // camera smoothing interpolation factor
};

// Node definitions
var hubNode = { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 };
var alphaNode = { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 };
var betaNode = { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 };
var gammaNode = { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 };
var deltaNode = { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 };
var epsilonNode = { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 };

var nodes = [hubNode, alphaNode, betaNode, gammaNode, deltaNode, epsilonNode];

// Edge/spring definitions (a and b are node IDs, rest = rest length, k = stiffness)
var edges = [
    { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var cameraActual = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle system
var particles = [];
var tickCount = 0;

/**
 * findNodeById - Searches the nodes array for a node with the given ID.
 * Returns the node object or null.
 */
function findNodeById(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

/**
 * updatePhysics - Runs one tick of the force-directed graph simulation:
 *   1. Coulomb-like repulsion between every pair of nodes
 *   2. Hooke's law spring forces along edges
 *   3. Gravity toward center (400, 300)
 *   4. Velocity damping (amplification factor)
 *   5. Euler integration of positions
 */
function updatePhysics() {
    // --- Pairwise repulsion (Coulomb's law) ---
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = simParams.attractionStrength / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // --- Spring forces along edges (Hooke's law) ---
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNodeById(edges[e].a);
        var nodeB = findNodeById(edges[e].b);
        if (!nodeA || !nodeB) continue;

        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || simParams.springCoeff) * displacement;

        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // --- Center gravity, damping, and position integration ---
    for (var n = 0; n < nodes.length; n++) {
        // Gravity toward center (400, 300)
        nodes[n].vx += (400 - nodes[n].x) * simParams.centerGravity;
        nodes[n].vy += (300 - nodes[n].y) * simParams.centerGravity;

        // Velocity damping
        nodes[n].vx *= simParams.amplification;
        nodes[n].vy *= simParams.amplification;

        // Euler integration
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

/**
 * spawnParticle - Creates a new decorative particle at a random node's position,
 * with a random direction and speed. Particles have a limited lifespan (maxAge).
 */
function spawnParticle() {
    if (particles.length >= simParams.streamCapacity) return;

    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
    });
}

/**
 * updateParticles - Advances all particles by one tick:
 *   - Applies drag (streamDecay)
 *   - Moves particles by their velocity
 *   - Increments age
 *   - Removes expired particles (age > maxAge)
 */
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];

        // Apply drag
        p.vx *= (1 - simParams.streamDecay * 0.125);
        p.vy *= (1 - simParams.streamDecay * 0.125);

        // Move
        p.x += p.vx;
        p.y += p.vy;

        // Age and remove if expired
        p.age++;
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

/**
 * updateCamera - Smoothly interpolates the actual camera position/zoom
 * toward the target camera using the theta parameter (lerp).
 */
function updateCamera() {
    cameraActual.x += (cameraTarget.x - cameraActual.x) * simParams.theta;
    cameraActual.y += (cameraTarget.y - cameraActual.y) * simParams.theta;
    cameraActual.zoom += (cameraTarget.zoom - cameraActual.zoom) * simParams.theta;
}

/**
 * mainLoop - The simulation tick called every 16ms (~60fps):
 *   1. Update physics (forces + integration)
 *   2. Update particles (move + expire)
 *   3. Update camera (smooth follow)
 *   4. Spawn a new particle every 3rd tick
 */
function mainLoop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    if (tickCount % 3 === 0) {
        spawnParticle();
    }
    tickCount++;
}

setInterval(mainLoop, 16);
```

